import { z } from 'zod';
import type { TimelineItem, TimelineContext } from './Timeline.js';

export interface EventOptions {
  condition?: (context: TimelineContext) => boolean;
  delay?: number;
  metadata?: Record<string, unknown>;
}

export abstract class Event implements TimelineItem {
  public readonly id: string;
  protected options: EventOptions;

  constructor(id: string, options: EventOptions = {}) {
    this.id = id;
    this.options = options;
  }

  protected abstract executeEvent(context: TimelineContext): Promise<void>;

  async execute(context: TimelineContext): Promise<void> {
    // Check condition if present
    if (this.options.condition && !this.options.condition(context)) {
      return;
    }

    // Apply delay if specified
    if (this.options.delay && this.options.delay > 0) {
      await new Promise(resolve => setTimeout(resolve, this.options.delay));
    }

    await this.executeEvent(context);
  }

  condition(predicate: (context: TimelineContext) => boolean): this {
    this.options.condition = predicate;
    return this;
  }

  delay(ms: number): this {
    this.options.delay = ms;
    return this;
  }

  metadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  serialize(): Record<string, unknown> {
    return {
      type: this.constructor.name,
      id: this.id,
      options: {
        delay: this.options.delay,
        metadata: this.options.metadata,
        // Note: condition functions cannot be serialized
      },
    };
  }

  duration?: number;
}

export class WaitEvent extends Event {
  private waitDuration: number;

  constructor(id: string, duration: number, options: EventOptions = {}) {
    super(id, options);
    this.waitDuration = duration;
    this.duration = duration;
  }

  protected async executeEvent(context: TimelineContext): Promise<void> {
    const startTime = context.clock.now();

    return new Promise((resolve) => {
      const checkTime = () => {
        const elapsed = context.clock.now() - startTime;
        if (elapsed >= this.waitDuration) {
          resolve();
        } else {
          requestAnimationFrame(checkTime);
        }
      };
      checkTime();
    });
  }

  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      waitDuration: this.waitDuration,
    };
  }

  static deserialize(data: Record<string, unknown>): WaitEvent {
    const schema = z.object({
      id: z.string(),
      waitDuration: z.number(),
      options: z.object({
        delay: z.number().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
    });

    const parsed = schema.parse(data);
    return new WaitEvent(parsed.id, parsed.waitDuration, parsed.options);
  }
}

export class ConditionalEvent extends Event {
  private trueEvent: TimelineItem;
  private falseEvent?: TimelineItem;
  private predicate: (context: TimelineContext) => boolean;

  constructor(
    id: string,
    predicate: (context: TimelineContext) => boolean,
    trueEvent: TimelineItem,
    falseEvent?: TimelineItem,
    options: EventOptions = {}
  ) {
    super(id, options);
    this.predicate = predicate;
    this.trueEvent = trueEvent;
    this.falseEvent = falseEvent;
  }

  protected async executeEvent(context: TimelineContext): Promise<void> {
    if (this.predicate(context)) {
      await this.trueEvent.execute(context);
    } else if (this.falseEvent) {
      await this.falseEvent.execute(context);
    }
  }

  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      trueEvent: 'serialize' in this.trueEvent ? this.trueEvent.serialize() : { id: this.trueEvent.id },
      falseEvent: this.falseEvent && 'serialize' in this.falseEvent ? this.falseEvent.serialize() : this.falseEvent ? { id: this.falseEvent.id } : undefined,
      // Note: predicate function cannot be serialized
    };
  }
}

export class LoopEvent extends Event {
  private loopBody: TimelineItem;
  private iterations: number;

  constructor(
    id: string,
    iterations: number,
    loopBody: TimelineItem,
    options: EventOptions = {}
  ) {
    super(id, options);
    this.iterations = iterations;
    this.loopBody = loopBody;
  }

  protected async executeEvent(context: TimelineContext): Promise<void> {
    for (let i = 0; i < this.iterations; i++) {
      const loopContext: TimelineContext = {
        ...context,
        data: { ...context.data, iteration: i },
      };
      await this.loopBody.execute(loopContext);
    }
  }

  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      iterations: this.iterations,
      loopBody: 'serialize' in this.loopBody ? this.loopBody.serialize() : { id: this.loopBody.id },
    };
  }

  static deserialize(data: Record<string, unknown>): LoopEvent {
    const schema = z.object({
      id: z.string(),
      iterations: z.number(),
      options: z.object({
        delay: z.number().optional(),
        metadata: z.record(z.unknown()).optional(),
      }).optional(),
      // Note: loopBody deserialization would need item registry
    });

    const parsed = schema.parse(data);
    // This is a simplified implementation - real deserialization would need
    // to reconstruct the loopBody from the serialized data
    throw new Error('LoopEvent deserialization requires item registry');
  }
}

export class DataEvent extends Event {
  private dataCollector: (context: TimelineContext) => Record<string, unknown>;

  constructor(
    id: string,
    dataCollector: (context: TimelineContext) => Record<string, unknown>,
    options: EventOptions = {}
  ) {
    super(id, options);
    this.dataCollector = dataCollector;
  }

  protected async executeEvent(context: TimelineContext): Promise<void> {
    const data = this.dataCollector(context);

    // Store data in context for later retrieval
    if (!context.data.collectedData) {
      context.data.collectedData = [];
    }
    (context.data.collectedData as Record<string, unknown>[]).push({
      eventId: this.id,
      timestamp: context.clock.now(),
      ...data,
    });
  }

  serialize(): Record<string, unknown> {
    return {
      ...super.serialize(),
      // Note: dataCollector function cannot be serialized
    };
  }
}

