  private preloadedVideo?: HTMLVideoElement;

  constructor(
    id: string,
    src: string | ((context: TimelineContext) => string),
    options: VideoStimulusOptions = {}
  ) {
    this.id = id;
    this.videoSrc = src;
    this.options = { 
      volume: 1.0,
      muted: false,
      autoplay: true,
      preload: true,
      controls: false,
