    return this;
  }

  blockedKeys(keyList: string[]): this {
    this.options.blockedKeys = keyList;
    return this;
  }

  metadata(data: Record<string, unknown>): this {
    this.options.metadata = data;
    return this;
  }

  private isKeyAllowed(key: string): boolean {
    // Check if key is in allowed list (if specified)
    if (this.options.allowedKeys && !this.options.allowedKeys.includes(key)) {
      return false;
    }

    // Check if key is in blocked list
    if (this.options.blockedKeys && this.options.blockedKeys.includes(key)) {
      return false;
    }

    // Check if key is in target keys list (if specified)
    if (this.options.keys && !this.options.keys.includes(key)) {
      return false;
    }

    return true;
  }

  private normalizeKey(key: string): string {
    return this.options.caseSensitive ? key : key.toLowerCase();
  }

  private determineCorrectness(key: string, context: TimelineContext): boolean | undefined {
    if (!this.options.correctResponse) {
      return undefined;
    }

    const correctKey = typeof this.options.correctResponse === 'function'
      ? this.options.correctResponse(context)
      : this.options.correctResponse;

    const normalizedKey = this.normalizeKey(key);
    const normalizedCorrect = this.normalizeKey(correctKey);

    return normalizedKey === normalizedCorrect;
  }

  async execute(context: TimelineContext): Promise<void> {
    const startTime = context.clock.now();
    this.responseData = undefined;

    // Show message if provided
    let messageElement: HTMLElement | undefined;
    if (this.options.message) {
      messageElement = document.createElement('div');
      messageElement.textContent = this.options.message;
      messageElement.style.position = 'absolute';
      messageElement.style.top = '20px';
      messageElement.style.left = '50%';
      messageElement.style.transform = 'translateX(-50%)';
      messageElement.style.padding = '10px';
      messageElement.style.backgroundColor = 'rgba(0, 0, 0, 0.8)';
      messageElement.style.color = 'white';
      messageElement.style.borderRadius = '4px';
      messageElement.style.zIndex = '9999';
      document.body.appendChild(messageElement);
    }

    try {
      // Get keyboard device from context or create default listener
      let keyboardDevice: KeyboardDevice | undefined;
      try {
        // This would need proper integration with DeviceManager
        // For now, we'll implement direct keyboard listening
      } catch (error) {
        // Fallback to direct event listening
      }

      return new Promise((resolve, reject) => {
        let timeoutId: number | undefined;
        let resolved = false;

        const handleKeyPress = (event: KeyboardEvent) => {
          if (resolved) return;

          const key = event.key;
          const timestamp = context.clock.now();

          // Check if key is allowed
          if (!this.isKeyAllowed(key)) {
            return; // Ignore this key press
          }

          // Prevent default behavior for handled keys
          event.preventDefault();

          // Create response data
          this.responseData = {
            key,
            code: event.code,
            timestamp,
            reactionTime: timestamp - startTime,
            correct: this.determineCorrectness(key, context),
            metadata: this.options.metadata,
          };

          // Store response in context
          if (!context.data.responses) {
            context.data.responses = [];
          }
          (context.data.responses as KeyboardResponseData[]).push(this.responseData);

          // Clean up and resolve
          cleanup();
          resolved = true;
          resolve();
        };

        const handleTimeout = () => {
          if (resolved) return;

          // Create timeout response data
          this.responseData = {
            key: '',
            code: '',
            timestamp: context.clock.now(),
            reactionTime: this.options.timeout!,
            correct: false,
            metadata: { ...this.options.metadata, timedOut: true },
          };

          // Store response in context
          if (!context.data.responses) {
            context.data.responses = [];
          }
          (context.data.responses as KeyboardResponseData[]).push(this.responseData);

          cleanup();
          resolved = true;
          resolve();
        };

        const cleanup = () => {
          document.removeEventListener('keydown', handleKeyPress);
          if (timeoutId !== undefined) {
            clearTimeout(timeoutId);
          }
          if (messageElement && messageElement.parentNode) {
            messageElement.parentNode.removeChild(messageElement);
          }
        };

        // Set up keyboard listener
        document.addEventListener('keydown', handleKeyPress);

        // Set up timeout if specified
        if (this.options.timeout) {
          timeoutId = window.setTimeout(handleTimeout, this.options.timeout);
        }
      });
    } catch (error) {
      // Clean up message element on error
      if (messageElement && messageElement.parentNode) {
        messageElement.parentNode.removeChild(messageElement);
      }
      throw error;
    }
  }

  getResponse(): KeyboardResponseData | undefined {
    return this.responseData;
  }

  serialize(): Record<string, unknown> {
    return {
      type: 'KeyboardResponse',
      id: this.id,
      options: {
        ...this.options,
        // Note: correctResponse function cannot be serialized
