import { describe, it, expect, vi, beforeEach } from 'vitest';
import { Timeline, type TimelineContext } from '../../src/core/Timeline.js';

describe('Timeline', () => {
  let mockContext: TimelineContext;

  beforeEach(() => {
    mockContext = {
      clock: {
        now: vi.fn(() => 1000),
      } as any,
      scheduler: {} as any,
      data: {},
    };
  });

  describe('constructor', () => {
    it('creates timeline with id and default options', () => {
      const timeline = new Timeline('test-timeline');
      expect(timeline.id).toBe('test-timeline');
      expect(timeline.getOptions()).toEqual({});
      expect(timeline.getItems()).toEqual([]);
    });

    it('creates timeline with custom options', () => {
      const options = { repeat: 5, randomize: true };
      const timeline = new Timeline('test-timeline', options);
      expect(timeline.getOptions()).toEqual(options);
    });
  });

  describe('fluent API', () => {
    it('allows method chaining', () => {
      const mockItem = {
        id: 'item1',
        execute: vi.fn(),
      };

      const timeline = new Timeline('test')
        .add(mockItem)
        .repeat(3)
        .randomize()
        .conditions([{ condition: 'A' }, { condition: 'B' }]);

      expect(timeline.getItems()).toHaveLength(1);
      expect(timeline.getOptions().repeat).toBe(3);
      expect(timeline.getOptions().randomize).toBe(true);
      expect(timeline.getOptions().conditions).toHaveLength(2);
    });
  });

  describe('item management', () => {
    it('adds items to timeline', () => {
      const timeline = new Timeline('test');
      const item1 = { id: 'item1', execute: vi.fn() };
      const item2 = { id: 'item2', execute: vi.fn() };

      timeline.add(item1).add(item2);

      expect(timeline.getItems()).toEqual([item1, item2]);
    });
  });

  describe('execution', () => {
    it('executes all items in order', async () => {
      const item1 = { id: 'item1', execute: vi.fn() };
      const item2 = { id: 'item2', execute: vi.fn() };

      const timeline = new Timeline('test')
        .add(item1)
        .add(item2);

      await timeline.execute(mockContext);

      expect(item1.execute).toHaveBeenCalledWith(expect.objectContaining({
        ...mockContext,
        trial: 0,
      }));
      expect(item2.execute).toHaveBeenCalledWith(expect.objectContaining({
        ...mockContext,
        trial: 1,
      }));
    });

    it('executes items multiple times when repeat is set', async () => {
      const item = { id: 'item1', execute: vi.fn() };

      const timeline = new Timeline('test')
        .add(item)
        .repeat(3);

      await timeline.execute(mockContext);

      expect(item.execute).toHaveBeenCalledTimes(3);
    });

    it('executes items for each condition', async () => {
      const item = { id: 'item1', execute: vi.fn() };
      const conditions = [{ type: 'A' }, { type: 'B' }];

      const timeline = new Timeline('test')
        .add(item)
        .conditions(conditions);

      await timeline.execute(mockContext);

      expect(item.execute).toHaveBeenCalledTimes(2);
      expect(item.execute).toHaveBeenCalledWith(expect.objectContaining({
        data: expect.objectContaining({ type: 'A' }),
        block: 0,
      }));
      expect(item.execute).toHaveBeenCalledWith(expect.objectContaining({
        data: expect.objectContaining({ type: 'B' }),
        block: 0,
      }));
    });

    it('combines repeat and conditions correctly', async () => {
      const item = { id: 'item1', execute: vi.fn() };
      const conditions = [{ type: 'A' }, { type: 'B' }];

      const timeline = new Timeline('test')
        .add(item)
        .repeat(2)
        .conditions(conditions);

      await timeline.execute(mockContext);

      // 2 repeats × 2 conditions = 4 executions
      expect(item.execute).toHaveBeenCalledTimes(4);
    });

    it('randomizes item order when randomize is true', async () => {
      const items = [
        { id: 'item1', execute: vi.fn() },
        { id: 'item2', execute: vi.fn() },
        { id: 'item3', execute: vi.fn() },
      ];

      const timeline = new Timeline('test')
        .add(items[0])
        .add(items[1])
        .add(items[2])
        .randomize();

      // Mock Math.random to control shuffling
      const originalRandom = Math.random;
      Math.random = vi.fn()
        .mockReturnValueOnce(0.8) // High value to trigger shuffle
        .mockReturnValueOnce(0.2); // Control second shuffle

      await timeline.execute(mockContext);

      // Verify all items were executed (order may vary due to randomization)
      items.forEach(item => {
        expect(item.execute).toHaveBeenCalled();
      });

      Math.random = originalRandom;
    });
  });

  describe('serialization', () => {
    it('serializes timeline with basic properties', () => {
      const timeline = new Timeline('test-timeline', {
        repeat: 3,
        randomize: true,
      });

      const serialized = timeline.serialize();

      expect(serialized).toEqual({
        type: 'Timeline',
        id: 'test-timeline',
        options: {
          repeat: 3,
          randomize: true,
        },
        items: [],
      });
    });

    it('serializes timeline with items', () => {
      const mockItem = {
        id: 'item1',
        execute: vi.fn(),
        serialize: vi.fn(() => ({ type: 'MockItem', id: 'item1' })),
      };

      const timeline = new Timeline('test-timeline')
        .add(mockItem);

      const serialized = timeline.serialize();

      expect(serialized.items).toEqual([
        { type: 'MockItem', id: 'item1' }
      ]);
    });

    it('handles items without serialize method', () => {
      const mockItem = {
        id: 'item1',
        execute: vi.fn(),
        metadata: { custom: 'data' },
      };

      const timeline = new Timeline('test-timeline')
        .add(mockItem);

      const serialized = timeline.serialize();

      expect(serialized.items).toEqual([
        {
          type: 'UnknownItem',
          id: 'item1',
          metadata: { custom: 'data' },
        }
      ]);
    });
  });

  describe('deserialization', () => {
    it('deserializes basic timeline', () => {
      const data = {
        id: 'test-timeline',
        options: {
          repeat: 2,
          randomize: false,
        },
      };

      const timeline = Timeline.deserialize(data);

      expect(timeline.id).toBe('test-timeline');
      expect(timeline.getOptions()).toEqual({
        repeat: 2,
        randomize: false,
      });
    });

    it('throws error for invalid data', () => {
      const invalidData = {
        // missing id
        options: {},
      };

      expect(() => Timeline.deserialize(invalidData)).toThrow();
    });
  });

  describe('metadata', () => {
    it('sets and gets metadata', () => {
      const metadata = { description: 'Test timeline' };
      const timeline = new Timeline('test')
        .metadata(metadata);

      expect(timeline.metadata).toEqual(metadata);
    });
  });
});

