import { describe, it, expect, vi, beforeEach } from 'vitest';
import { WaitEvent, ConditionalEvent, LoopEvent, DataEvent, type TimelineContext } from '../../src/core/Event.js';

describe('Event classes', () => {
  let mockContext: TimelineContext;

  beforeEach(() => {
    mockContext = {
      clock: {
        now: vi.fn(() => 1000),
      } as any,
      scheduler: {} as any,
      data: {},
    };
  });

  describe('WaitEvent', () => {
    it('creates wait event with duration', () => {
      const waitEvent = new WaitEvent('wait1', 500);
      expect(waitEvent.id).toBe('wait1');
      expect(waitEvent.duration).toBe(500);
    });

    it('waits for specified duration', async () => {
      let currentTime = 1000;
      mockContext.clock.now = vi.fn(() => currentTime);

      const waitEvent = new WaitEvent('wait1', 100);

      // Mock requestAnimationFrame to advance time
      const originalRAF = global.requestAnimationFrame;
      global.requestAnimationFrame = vi.fn((callback) => {
        currentTime += 50; // Advance by 50ms each frame
        setTimeout(callback, 0);
        return 1;
      });

      const startTime = Date.now();
      await waitEvent.execute(mockContext);
      const endTime = Date.now();

      expect(endTime - startTime).toBeGreaterThanOrEqual(0); // Some time should have passed

      global.requestAnimationFrame = originalRAF;
    });

    it('serializes correctly', () => {
      const waitEvent = new WaitEvent('wait1', 500);
      const serialized = waitEvent.serialize();

      expect(serialized).toEqual({
        type: 'WaitEvent',
        id: 'wait1',
        options: {},
        waitDuration: 500,
      });
    });

    it('deserializes correctly', () => {
      const data = {
        id: 'wait1',
        waitDuration: 500,
        options: { delay: 100 },
      };

      const waitEvent = WaitEvent.deserialize(data);
      expect(waitEvent.id).toBe('wait1');
      expect(waitEvent.duration).toBe(500);
    });
  });

  describe('ConditionalEvent', () => {
    it('executes true branch when condition is true', async () => {
      const trueItem = { id: 'true-item', execute: vi.fn() };
      const falseItem = { id: 'false-item', execute: vi.fn() };
      const condition = vi.fn(() => true);

      const conditionalEvent = new ConditionalEvent(
        'cond1',
        condition,
        trueItem,
        falseItem
      );

      await conditionalEvent.execute(mockContext);

      expect(condition).toHaveBeenCalledWith(mockContext);
      expect(trueItem.execute).toHaveBeenCalledWith(mockContext);
      expect(falseItem.execute).not.toHaveBeenCalled();
    });

    it('executes false branch when condition is false', async () => {
      const trueItem = { id: 'true-item', execute: vi.fn() };
      const falseItem = { id: 'false-item', execute: vi.fn() };
