import { describe, it, expect, vi, beforeEach } from 'vitest';
import { TextStimulus } from '../../src/stimuli/Text.js';
import type { TimelineContext } from '../../src/core/Timeline.js';

describe('TextStimulus', () => {
  let mockContext: TimelineContext;

  beforeEach(() => {
    mockContext = {
      clock: {
        now: vi.fn(() => 1000),
      } as any,
      scheduler: {} as any,
      data: {},
    };

    // Reset document.body mock
    document.body.appendChild = vi.fn();
    document.body.removeChild = vi.fn();
  });

  describe('constructor', () => {
    it('creates text stimulus with string content', () => {
      const stimulus = new TextStimulus('text1', 'Hello World');
      expect(stimulus.id).toBe('text1');
    });

    it('creates text stimulus with function content', () => {
      const textFn = vi.fn(() => 'Dynamic text');
      const stimulus = new TextStimulus('text1', textFn);
      expect(stimulus.id).toBe('text1');
    });
  });

  describe('fluent API', () => {
    it('allows method chaining', () => {
      const stimulus = new TextStimulus('text1', 'Hello')
        .duration(1000)
        .position(100, 200)
        .fontSize(24)
        .color('red')
        .backgroundColor('blue')
        .opacity(0.8);

      expect(stimulus.duration).toBe(1000);
    });

    it('sets position correctly', () => {
      const stimulus = new TextStimulus('text1', 'Hello')
        .position(150, 250);

      const serialized = stimulus.serialize();
      expect(serialized.options).toEqual(
        expect.objectContaining({
          position: { x: 150, y: 250 },
        })
      );
    });

    it('sets font properties correctly', () => {
      const stimulus = new TextStimulus('text1', 'Hello')
        .fontSize(20)
        .fontFamily('Arial');

      const serialized = stimulus.serialize();
      expect(serialized.options).toEqual(
        expect.objectContaining({
          fontSize: 20,
          fontFamily: 'Arial',
        })
      );
    });

    it('sets color properties correctly', () => {
      const stimulus = new TextStimulus('text1', 'Hello')
        .color('#ff0000')
        .backgroundColor('#0000ff');

      const serialized = stimulus.serialize();
      expect(serialized.options).toEqual(
        expect.objectContaining({
          color: '#ff0000',
          backgroundColor: '#0000ff',
        })
      );
    });

    it('clamps opacity between 0 and 1', () => {
      const stimulus1 = new TextStimulus('text1', 'Hello').opacity(-0.5);
      const stimulus2 = new TextStimulus('text2', 'Hello').opacity(1.5);

      expect(stimulus1.serialize().options).toEqual(
        expect.objectContaining({ opacity: 0 })
      );
      expect(stimulus2.serialize().options).toEqual(
        expect.objectContaining({ opacity: 1 })
      );
    });

    it('sets visual effects correctly', () => {
      const stimulus = new TextStimulus('text1', 'Hello')
        .rotation(45)
        .scale(1.5)
        .zIndex(10);

      const serialized = stimulus.serialize();
      expect(serialized.options).toEqual(
        expect.objectContaining({
          rotation: 45,
          scale: 1.5,
          zIndex: 10,
        })
      );
    });

    it('sets CSS properties correctly', () => {
      const stimulus = new TextStimulus('text1', 'Hello')
        .className('my-class')
        .style({ border: '1px solid black', padding: '10px' });

      const serialized = stimulus.serialize();
      expect(serialized.options).toEqual(
        expect.objectContaining({
          className: 'my-class',
          // Note: style is excluded from serialization
        })
      );
    });
  });

  describe('execution', () => {
    it('creates and displays text element', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const stimulus = new TextStimulus('text1', 'Hello World', { duration: 100 });

      await stimulus.execute(mockContext);

      expect(document.createElement).toHaveBeenCalledWith('div');
      expect(mockElement.textContent).toBe('Hello World');
      expect(document.body.appendChild).toHaveBeenCalledWith(mockElement);
    });

    it('uses function to generate dynamic text', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const textFn = vi.fn(() => 'Dynamic content');
      const stimulus = new TextStimulus('text1', textFn, { duration: 100 });

      await stimulus.execute(mockContext);

      expect(textFn).toHaveBeenCalledWith(mockContext);
      expect(mockElement.textContent).toBe('Dynamic content');
    });

    it('applies position styles correctly', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const stimulus = new TextStimulus('text1', 'Hello')
        .position(100, 200)
        .duration(100);

      await stimulus.execute(mockContext);

      expect(mockElement.style.left).toBe('100px');
      expect(mockElement.style.top).toBe('200px');
    });

    it('centers text by default', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const stimulus = new TextStimulus('text1', 'Hello', { duration: 100 });

      await stimulus.execute(mockContext);

      expect(mockElement.style.left).toBe('50%');
      expect(mockElement.style.top).toBe('50%');
      expect(mockElement.style.transform).toBe('translate(-50%, -50%)');
    });

    it('applies text styling correctly', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const stimulus = new TextStimulus('text1', 'Hello')
        .fontSize(24)
        .fontFamily('Arial')
        .color('red')
        .duration(100);

      await stimulus.execute(mockContext);

      expect(mockElement.style.fontSize).toBe('24px');
      expect(mockElement.style.fontFamily).toBe('Arial');
      expect(mockElement.style.color).toBe('red');
    });

    it('applies visual effects correctly', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const stimulus = new TextStimulus('text1', 'Hello')
        .rotation(45)
        .scale(1.5)
        .opacity(0.8)
        .duration(100);

      await stimulus.execute(mockContext);

      expect(mockElement.style.transform).toContain('rotate(45deg)');
      expect(mockElement.style.transform).toContain('scale(1.5)');
      expect(mockElement.style.opacity).toBe('0.8');
    });

    it('removes element after duration', async () => {
      let currentTime = 1000;
      mockContext.clock.now = vi.fn(() => currentTime);

      const mockElement = document.createElement('div');
      mockElement.parentNode = document.body;
      document.createElement = vi.fn(() => mockElement);

      const originalRAF = global.requestAnimationFrame;
      global.requestAnimationFrame = vi.fn((callback) => {
        currentTime += 50; // Advance time
        setTimeout(callback, 0);
        return 1;
      });

      const stimulus = new TextStimulus('text1', 'Hello', { duration: 100 });

      await stimulus.execute(mockContext);

      expect(document.body.removeChild).toHaveBeenCalledWith(mockElement);

      global.requestAnimationFrame = originalRAF;
    });

    it('does not auto-remove when duration is not specified', async () => {
      const mockElement = document.createElement('div');
      document.createElement = vi.fn(() => mockElement);

      const stimulus = new TextStimulus('text1', 'Hello');

      await stimulus.execute(mockContext);

      expect(document.body.appendChild).toHaveBeenCalledWith(mockElement);
      expect(document.body.removeChild).not.toHaveBeenCalled();
    });
  });

  describe('manual control', () => {
    it('hides element when hide() is called', () => {
      const mockElement = document.createElement('div');
      mockElement.parentNode = document.body;

      const stimulus = new TextStimulus('text1', 'Hello');
      stimulus['element'] = mockElement;

      stimulus.hide();

      expect(document.body.removeChild).toHaveBeenCalledWith(mockElement);
    });

    it('handles hide() when element is not displayed', () => {
      const stimulus = new TextStimulus('text1', 'Hello');

      // Should not throw an error
      expect(() => stimulus.hide()).not.toThrow();
    });
  });

  describe('serialization', () => {
    it('serializes with string content', () => {
      const stimulus = new TextStimulus('text1', 'Hello World', {
        duration: 1000,
        fontSize: 24,
      });

      const serialized = stimulus.serialize();

      expect(serialized).toEqual({
        type: 'TextStimulus',
        id: 'text1',
        text: 'Hello World',
        options: {
          duration: 1000,
          fontSize: 24,
          style: undefined, // Excluded from serialization
        },
      });
    });

    it('serializes with function content as placeholder', () => {
      const textFn = () => 'Dynamic';
      const stimulus = new TextStimulus('text1', textFn);

      const serialized = stimulus.serialize();

      expect(serialized.text).toBe('[Function]');
    });
  });

  describe('deserialization', () => {
    it('deserializes correctly', () => {
      const data = {
        id: 'text1',
        text: 'Hello World',
        options: {
          duration: 1000,
          fontSize: 24,
          color: 'red',
        },
      };

      const stimulus = TextStimulus.deserialize(data);

      expect(stimulus.id).toBe('text1');
      expect(stimulus.duration).toBe(1000);
    });

    it('handles missing options', () => {
      const data = {
        id: 'text1',
        text: 'Hello World',
      };

      const stimulus = TextStimulus.deserialize(data);

      expect(stimulus.id).toBe('text1');
      expect(stimulus.duration).toBeUndefined();
    });

    it('throws error for invalid data', () => {
      const invalidData = {
        // missing id and text
        options: {},
      };

      expect(() => TextStimulus.deserialize(invalidData)).toThrow();
    });
  });

  describe('metadata', () => {
    it('sets and gets metadata', () => {
      const metadata = { description: 'Test stimulus' };
      const stimulus = new TextStimulus('text1', 'Hello')
        .metadata(metadata);

      expect(stimulus.metadata).toEqual(metadata);
    });
  });
});

