        id: 'text1',
        text: 'Hello World',
        options: {
          duration: 1000,
          fontSize: 24,
          color: 'red',
        },
      };

      const stimulus = TextStimulus.deserialize(data);

      expect(stimulus.id).toBe('text1');
      expect(stimulus.duration).toBe(1000);
    });

    it('handles missing options', () => {
      const data = {
        id: 'text1',
        text: 'Hello World',
      };

      const stimulus = TextStimulus.deserialize(data);

      expect(stimulus.id).toBe('text1');
      expect(stimulus.duration).toBeUndefined();
    });

    it('throws error for invalid data', () => {
      const invalidData = {
        // missing id and text
        options: {},
      };

      expect(() => TextStimulus.deserialize(invalidData)).toThrow();
    });
  });

  describe('metadata', () => {
    it('sets and gets metadata', () => {
      const metadata = { description: 'Test stimulus' };
      const stimulus = new TextStimulus('text1', 'Hello')
        .metadata(metadata);

      expect(stimulus.metadata).toEqual(metadata);
    });
  });
});

