import { describe, it, expect, vi, beforeEach } from 'vitest';
import { KeyboardResponse } from '../../src/responses/KeyboardResponse.js';
import type { TimelineContext } from '../../src/core/Timeline.js';

describe('KeyboardResponse', () => {
  let mockContext: TimelineContext;

  beforeEach(() => {
    mockContext = {
      clock: {
        now: vi.fn(() => 1000),
      } as any,
      scheduler: {} as any,
      data: {},
    };

    // Reset document event listeners
    document.addEventListener = vi.fn();
    document.removeEventListener = vi.fn();
    document.body.appendChild = vi.fn();
    document.body.removeChild = vi.fn();

    // Clear any existing timeout
    vi.clearAllTimers();
  });

  describe('constructor', () => {
    it('creates keyboard response with default options', () => {
      const response = new KeyboardResponse('kb1');
      expect(response.id).toBe('kb1');
    });

    it('creates keyboard response with custom options', () => {
      const options = { keys: ['f', 'j'], timeout: 5000 };
      const response = new KeyboardResponse('kb1', options);
      expect(response.id).toBe('kb1');
    });
  });

  describe('fluent API', () => {
    it('allows method chaining', () => {
      const response = new KeyboardResponse('kb1')
        .keys(['f', 'j'])
        .timeout(3000)
        .message('Press F or J')
        .correctResponse('f')
        .caseSensitive(true);

      expect(response.id).toBe('kb1');
    });

    it('sets allowed and blocked keys', () => {
      const response = new KeyboardResponse('kb1')
        .allowedKeys(['a', 'b', 'c'])
        .blockedKeys(['Escape']);

      const serialized = response.serialize();
      expect(serialized.options).toEqual(
        expect.objectContaining({
          allowedKeys: ['a', 'b', 'c'],
          blockedKeys: ['Escape'],
        })
      );
    });

    it('sets correct response as string or function', () => {
      const response1 = new KeyboardResponse('kb1').correctResponse('f');
      const response2 = new KeyboardResponse('kb2').correctResponse(() => 'j');

      // Functions can't be serialized, so we check the type
      expect(response1.serialize().options.correctResponse).toBe('f');
      expect(response2.serialize().options.correctResponse).toBe('[Function]');
    });
  });

  describe('key filtering', () => {
    let response: KeyboardResponse;
    let mockEvent: KeyboardEvent;

    beforeEach(() => {
      response = new KeyboardResponse('kb1');
      mockEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(mockEvent, 'preventDefault', { value: vi.fn() });
    });

    it('accepts any key when no restrictions', async () => {
      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      // Simulate key press
      keyPressHandler!(mockEvent);

      await executePromise;

      expect(mockContext.data.responses).toHaveLength(1);
    });

    it('filters by target keys', async () => {
      response.keys(['f', 'j']);

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      // Simulate pressing an invalid key
      const invalidEvent = new KeyboardEvent('keydown', { key: 'x' });
      keyPressHandler!(invalidEvent);

      // Simulate pressing a valid key
      setTimeout(() => {
        keyPressHandler!(mockEvent);
      }, 10);

      await executePromise;

      expect(mockContext.data.responses).toHaveLength(1);
      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({ key: 'f' })
      );
    });

    it('blocks specified keys', async () => {
      response.blockedKeys(['Escape']);

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      // Simulate pressing a blocked key
      const blockedEvent = new KeyboardEvent('keydown', { key: 'Escape' });
      keyPressHandler!(blockedEvent);

      // Simulate pressing an allowed key
      setTimeout(() => {
        keyPressHandler!(mockEvent);
      }, 10);

      await executePromise;

      expect(mockContext.data.responses).toHaveLength(1);
      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({ key: 'f' })
      );
    });
  });

  describe('correctness evaluation', () => {
    it('evaluates correct response with string', async () => {
      const response = new KeyboardResponse('kb1')
        .correctResponse('f');

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      const correctEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(correctEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(correctEvent);

      await executePromise;

      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({ correct: true })
      );
    });

    it('evaluates incorrect response', async () => {
      const response = new KeyboardResponse('kb1')
        .correctResponse('f');

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      const incorrectEvent = new KeyboardEvent('keydown', { key: 'j' });
      Object.defineProperty(incorrectEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(incorrectEvent);

      await executePromise;

      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({ correct: false })
      );
    });

    it('handles case sensitivity', async () => {
      const response = new KeyboardResponse('kb1')
        .correctResponse('F')
        .caseSensitive(true);

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      const lowercaseEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(lowercaseEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(lowercaseEvent);

      await executePromise;

      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({ correct: false })
      );
    });

    it('ignores case when case insensitive', async () => {
      const response = new KeyboardResponse('kb1')
        .correctResponse('F')
        .caseSensitive(false);

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      const lowercaseEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(lowercaseEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(lowercaseEvent);

      await executePromise;

      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({ correct: true })
      );
    });
  });

  describe('timeout handling', () => {
    it('times out when no response within timeout period', async () => {
      vi.useFakeTimers();

      const response = new KeyboardResponse('kb1').timeout(1000);

      document.addEventListener = vi.fn();

      const executePromise = response.execute(mockContext);

      // Fast-forward time to trigger timeout
      vi.advanceTimersByTime(1000);

      await executePromise;

      expect(mockContext.data.responses).toHaveLength(1);
      expect(mockContext.data.responses[0]).toEqual(
        expect.objectContaining({
          key: '',
          correct: false,
          reactionTime: 1000,
          metadata: expect.objectContaining({ timedOut: true }),
        })
      );

      vi.useRealTimers();
    });
  });

  describe('message display', () => {
    it('displays message when provided', async () => {
      const response = new KeyboardResponse('kb1')
        .message('Press any key');

      const mockMessageElement = document.createElement('div');
      let createElementCallCount = 0;
      document.createElement = vi.fn(() => {
        createElementCallCount++;
        return mockMessageElement;
      });

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      expect(document.createElement).toHaveBeenCalledWith('div');
      expect(mockMessageElement.textContent).toBe('Press any key');
      expect(document.body.appendChild).toHaveBeenCalledWith(mockMessageElement);

      // Simulate key press to complete
      const keyEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(keyEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(keyEvent);

      await executePromise;

      expect(document.body.removeChild).toHaveBeenCalledWith(mockMessageElement);
    });
  });

  describe('response data', () => {
    it('collects comprehensive response data', async () => {
      let currentTime = 1000;
      mockContext.clock.now = vi.fn(() => currentTime);

      const response = new KeyboardResponse('kb1')
        .metadata({ trial: 1 });

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      // Advance time and simulate key press
      currentTime = 1150; // 150ms reaction time
      const keyEvent = new KeyboardEvent('keydown', { key: 'f', code: 'KeyF' });
      Object.defineProperty(keyEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(keyEvent);

      await executePromise;

      expect(mockContext.data.responses[0]).toEqual({
        key: 'f',
        code: 'KeyF',
        timestamp: 1150,
        reactionTime: 150,
        correct: undefined, // No correct response specified
        metadata: { trial: 1 },
      });
    });

    it('provides access to response data', async () => {
      const response = new KeyboardResponse('kb1');

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      const keyEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(keyEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(keyEvent);

      await executePromise;

      const responseData = response.getResponse();
      expect(responseData).toEqual(
        expect.objectContaining({ key: 'f' })
      );
    });
  });

  describe('serialization', () => {
    it('serializes correctly', () => {
      const response = new KeyboardResponse('kb1', {
        keys: ['f', 'j'],
        timeout: 5000,
        correctResponse: 'f',
      });

      const serialized = response.serialize();

      expect(serialized).toEqual({
        type: 'KeyboardResponse',
        id: 'kb1',
        options: {
          keys: ['f', 'j'],
          timeout: 5000,
          correctResponse: 'f',
          caseSensitive: undefined,
          allowedKeys: undefined,
          blockedKeys: undefined,
          message: undefined,
          metadata: undefined,
        },
        responseData: undefined,
      });
    });

    it('handles function correctResponse in serialization', () => {
      const response = new KeyboardResponse('kb1')
        .correctResponse(() => 'dynamic');

      const serialized = response.serialize();
      expect(serialized.options.correctResponse).toBe('[Function]');
    });
  });

  describe('deserialization', () => {
    it('deserializes correctly', () => {
      const data = {
        id: 'kb1',
        options: {
          keys: ['f', 'j'],
          timeout: 5000,
          correctResponse: 'f',
        },
      };

      const response = KeyboardResponse.deserialize(data);

      expect(response.id).toBe('kb1');
      expect(response.duration).toBe(5000);
    });

    it('handles missing options', () => {
      const data = {
        id: 'kb1',
      };

      const response = KeyboardResponse.deserialize(data);

      expect(response.id).toBe('kb1');
      expect(response.duration).toBeUndefined();
    });

    it('throws error for invalid data', () => {
      const invalidData = {
        // missing id
        options: {},
      };

      expect(() => KeyboardResponse.deserialize(invalidData)).toThrow();
    });
  });

  describe('cleanup', () => {
    it('removes event listeners after response', async () => {
      const response = new KeyboardResponse('kb1');

      let keyPressHandler: (event: KeyboardEvent) => void;

      document.addEventListener = vi.fn((event, handler) => {
        if (event === 'keydown') {
          keyPressHandler = handler as (event: KeyboardEvent) => void;
        }
      });

      const executePromise = response.execute(mockContext);

      const keyEvent = new KeyboardEvent('keydown', { key: 'f' });
      Object.defineProperty(keyEvent, 'preventDefault', { value: vi.fn() });
      keyPressHandler!(keyEvent);

      await executePromise;

      expect(document.removeEventListener).toHaveBeenCalledWith('keydown', keyPressHandler);
    });
  });
});

