/**
 * Classic Stroop Color-Word Interference Task
 * 
 * This example demonstrates:
 * - Timeline creation and nesting
 * - Dynamic stimulus content
 * - Response collection and validation
 * - Conditional logic and randomization
 * - Data collection and analysis
 */

import { ForgeScript } from '../src/index.js';

// Create the experiment
const stroopExperiment = ForgeScript.createExperiment('Stroop Color-Word Task')
  .title('Stroop Color-Word Interference Task')
  .description('A classic cognitive psychology experiment measuring selective attention and processing speed')
  .version('1.0.0')
  .author('Psychology Research Lab')
  .tags(['attention', 'stroop', 'cognitive psychology', 'interference']);

// Define stimulus sets
const colorWords = ['RED', 'GREEN', 'BLUE', 'YELLOW'];
const colors = ['red', 'green', 'blue', 'yellow'];
const keyMapping = { 'red': 'r', 'green': 'g', 'blue': 'b', 'yellow': 'y' };

// Welcome and consent
const welcomeTimeline = ForgeScript.createTimeline('welcome')
  .add(ForgeScript.createTextStimulus('Welcome to the Stroop Task!', 3000)
    .fontSize(36)
    .color('black'))
  .add(ForgeScript.createTextStimulus(
    'In this experiment, you will see words displayed in different colors.\n\n' +
    'Your task is to identify the COLOR of the text, not the word itself.\n\n' +
    'Press SPACE to continue...'
  )
    .fontSize(20)
    .color('black'))
  .add(ForgeScript.createKeyboardResponse(['space']));

// Instructions with examples
const instructionsTimeline = ForgeScript.createTimeline('instructions')
  .add(ForgeScript.createTextStimulus(
    'Response Keys:\n\n' +
    'R = Red    G = Green    B = Blue    Y = Yellow\n\n' +
    'Remember: Respond to the COLOR, not the word!', 5000
  )
    .fontSize(18)
    .color('black'))
  .add(ForgeScript.createTextStimulus('Let\'s try a few practice trials...', 2000)
    .fontSize(20)
    .color('black'));

// Practice trials
const practiceConditions = [
  { word: 'RED', color: 'red', congruent: true },
  { word: 'BLUE', color: 'green', congruent: false },
  { word: 'GREEN', color: 'blue', congruent: false },
];

const practiceTimeline = ForgeScript.createTimeline('practice')
  .conditions(practiceConditions)
  .add(ForgeScript.createTextStimulus('+', 500)
    .fontSize(24)
    .color('black')) // fixation cross
  .add(ForgeScript.createTextStimulus((context: any) => context.data.word)
    .color((context: any) => context.data.color)
    .fontSize(48)
    .duration(2000))
  .add(ForgeScript.createKeyboardResponse(['r', 'g', 'b', 'y'], 3000)
    .correctResponse((context: any) => keyMapping[context.data.color])
    .message('R = Red, G = Green, B = Blue, Y = Yellow'))
  .add(ForgeScript.createTextStimulus((context: any) => {
    const response = context.data.responses[context.data.responses.length - 1];
    return response.correct ? 'Correct!' : 'Incorrect. Remember to respond to the COLOR.';
  }, 1500)
    .color((context: any) => {
      const response = context.data.responses[context.data.responses.length - 1];
      return response.correct ? 'green' : 'red';
    }));

// Create main experimental conditions
const generateTrialConditions = (numTrials: number) => {
  const conditions = [];

  for (let i = 0; i < numTrials; i++) {
    const word = colorWords[Math.floor(Math.random() * colorWords.length)];
    const color = colors[Math.floor(Math.random() * colors.length)];
    const congruent = word.toLowerCase() === color;

    conditions.push({
      word,
      color,
      congruent,
      trial: i + 1,
    });
  }

  return conditions;
};

// Main experimental trials
const mainTimeline = ForgeScript.createTimeline('main-trials')
  .conditions(generateTrialConditions(80)) // 80 trials
  .randomize()
  .add(ForgeScript.createTextStimulus('+', 500)
    .fontSize(24)
    .color('black')) // fixation cross
  .add(ForgeScript.createTextStimulus((context: any) => context.data.word)
    .color((context: any) => context.data.color)
    .fontSize(48)
    .duration(0)) // No automatic timeout
  .add(ForgeScript.createKeyboardResponse(['r', 'g', 'b', 'y'], 5000)
    .correctResponse((context: any) => keyMapping[context.data.color]))
  .add(ForgeScript.createWaitEvent(250)); // Brief inter-trial interval

// Break every 20 trials
const breakTimeline = ForgeScript.createTimeline('break')
  .add(ForgeScript.createTextStimulus(
    'Take a short break.\n\nPress SPACE when ready to continue...', 0
  )
    .fontSize(20)
    .color('black'))
  .add(ForgeScript.createKeyboardResponse(['space']));

// Completion and thanks
const completionTimeline = ForgeScript.createTimeline('completion')
  .add(ForgeScript.createTextStimulus('Task Complete!', 2000)
    .fontSize(36)
    .color('green'))
  .add(ForgeScript.createTextStimulus(
    'Thank you for participating!\n\nYour data has been saved.', 3000
  )
    .fontSize(20)
    .color('black'));

// Assemble the complete experiment
stroopExperiment.timeline([
  welcomeTimeline,
  instructionsTimeline,
  practiceTimeline,
  mainTimeline,
  completionTimeline,
]);

// Add data processing callback
stroopExperiment.onComplete((data) => {
  console.log('Experiment completed!');
  console.log(`Total responses: ${data.responses.length}`);

  // Calculate basic statistics
  const responses = data.responses as any[];
  const correctResponses = responses.filter(r => r.correct);
  const accuracy = correctResponses.length / responses.length;

  const congruentTrials = responses.filter((r, i) => {
    return data.collectedData[i]?.congruent;
  });
  const incongruentTrials = responses.filter((r, i) => {
    return data.collectedData[i]?.congruent === false;
  });

  const avgRTCongruent = congruentTrials.reduce((sum, r) => sum + r.reactionTime, 0) / congruentTrials.length;
  const avgRTIncongruent = incongruentTrials.reduce((sum, r) => sum + r.reactionTime, 0) / incongruentTrials.length;

  console.log(`Accuracy: ${(accuracy * 100).toFixed(1)}%`);
  console.log(`Average RT (Congruent): ${avgRTCongruent.toFixed(0)}ms`);
  console.log(`Average RT (Incongruent): ${avgRTIncongruent.toFixed(0)}ms`);
  console.log(`Stroop Effect: ${(avgRTIncongruent - avgRTCongruent).toFixed(0)}ms`);
});

// Export for use
export default stroopExperiment;

// Example usage:
/*
import stroopExperiment from './stroop-task.js';

// Run the experiment
stroopExperiment.run('participant_001').then((data) => {
  console.log('Experiment data:', data);
}).catch((error) => {
  console.error('Experiment failed:', error);
});
*/

